local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxArenaCtrl:LxBaseCtrl
local LxArenaCtrl = classX("LxArenaCtrl", LxBaseCtrl)

function LxArenaCtrl:Initialize()
    LxBaseCtrl.Initialize(self)

end
---获取演武场数据列表，没有协议，要自己加
function LxArenaCtrl:GetGameInletDataList()
    local res = {}
    local arena = ModuleCenter.Arena:GetArenaData()
    if(arena ~= nil)then
        table.insert(res,{
            refId = 101,
            endTime = arena.seasonEndTime
        })
    end

    local dailyCfg = GameTable.GameInletRef[102]
    if CtrlCenter.FuncOpen:IsFuncOpen(dailyCfg.jumpId) then
        --添加日常副本入口
        table.insert(res,{
            refId = 102,
            endTime = LxUtil.GetZeroTimeStamp() * 1000
        })
    end

    return res
end
---获取最大挑战次数
function LxArenaCtrl:GetMaxAttackCount()
    local count = 0;
    for i, v in pairs(GameTable.ArenaChallengeAwardRef) do
        if(v.rank > count)then
            count = v.rank
        end
    end
    return count;
end
function LxArenaCtrl:GetBoxMaxId()
    local id = 0;
    for i, v in pairs(GameTable.ArenaChallengeAwardRef) do
        if(v.rank > id)then
            id = v.refId
        end
    end
    return id;
end
function LxArenaCtrl:GetMyScore()
    return ModuleCenter.Arena:GetScore()
end
function LxArenaCtrl:GetMyRank()
    return ModuleCenter.Arena:GetRank()
end
function LxArenaCtrl:BoxIsReward(id)
    local alreadyReward = ModuleCenter.Arena:GetArenaData().alreadyGet
    for i, v in ipairs(alreadyReward) do
        if(id == v)then
            return true
        end
    end
    return false
end

function LxArenaCtrl:GetTargetDefFormation(roleId)
    local formation = ModuleCenter.Arena:GetTargetFormation(roleId)
    if(formation ~= nil and formation.type == BattleType.Arena)then
        return formation.defendFormations[1]
    end
    return nil
end
---判断战报自己是否胜利
---@param data LxArenaRecordInfo
function LxArenaCtrl:ReportOwnerIsWin(data)
    local roleId = ModuleCenter.Role:GetRoleInfo().roleId
    if(roleId == data.attRoleInfo.roleInfo.roleId)then
        --自己是进攻方
        if(data.isWin)then
            return true
        end
    else
        --自己是防守方
        if(data.isWin == false)then
            return true
        end
    end
    return false
end
---获取战报，对方名字
---@param data LxArenaRecordInfo
function LxArenaCtrl:ReportTargetName(data)
    local roleId = ModuleCenter.Role:GetRoleInfo().roleId
    if(roleId == data.defRoleInfo.roleInfo.roleId)then
        --自己是防守方
        return data.attRoleInfo.roleInfo.name
    else
        --自己是进攻方
        return data.defRoleInfo.roleInfo.name
    end
end
---获取战报，对方战力
---@param data LxArenaRecordInfo
function LxArenaCtrl:ReportTargetPower(data)
    local roleId = ModuleCenter.Role:GetRoleInfo().roleId
    if(roleId == data.defRoleInfo.roleInfo.roleId)then
        --自己是防守方
        return data.attRoleInfo.roleInfo.power
    else
        --自己是进攻方
        return data.defRoleInfo.roleInfo.power
    end
end
---判断战报自己获得了多少积分
---@param data LxArenaRecordInfo
function LxArenaCtrl:ReportOwnerScore(data)
    local roleId = ModuleCenter.Role:GetRoleInfo().roleId
    if(roleId == data.attRoleInfo.roleInfo.roleId)then
        --自己是进攻方
        if(data.attRoleInfo.score >= 0)then
            return string.replace(I18nText(10123),data.attRoleInfo.score)
        end
        return data.attRoleInfo.score
    else
        if(data.attRoleInfo.score >= 0)then
            return string.replace(I18nText(10124),data.attRoleInfo.score)
        end
        return data.defRoleInfo.score
    end
end
---战报，获取对面玩家信息
---@param data LxArenaRecordInfo
function LxArenaCtrl:ReportTargetRoleInfo(data)
    local roleId = ModuleCenter.Role:GetRoleInfo().roleId
    if(roleId == data.attRoleInfo.roleInfo.roleId)then
        --自己是进攻方
        return data.attRoleInfo.roleInfo
    else
        return data.defRoleInfo.roleInfo
    end
end

function LxArenaCtrl:GetReportList()
    local list = ModuleCenter.Arena:GetReportList()
    table.sort(list, function(a,b)
        return a.time > b.time
    end)
    return list
end
function LxArenaCtrl:GetArenaRed()
    local box = self:GetBoxReceiveRed()
    local freeCount = self:GetArenaFreeCountRed()
    return box or freeCount
end
function LxArenaCtrl:GetBoxReceiveRed()
    local arenaData = ModuleCenter.Arena:GetArenaData()
    for i, v in pairs(GameTable.ArenaChallengeAwardRef) do
        if(self:BoxIsReward(v.refId) == false)then
            if(arenaData.seasonCount >= v.rank)then
                return true
            end

        end
    end
    return false
end
function LxArenaCtrl:GetArenaFreeCountRed()
    local arenaData = ModuleCenter.Arena:GetArenaData()
    if(arenaData.freeCount > 0)then
        return true
    end
    return false
end
function LxArenaCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

return LxArenaCtrl